import { Component, Inject, OnInit } from '@angular/core';
import { UntypedFormBuilder, UntypedFormGroup } from '@angular/forms';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { Groups } from '../interfaces/groups.model';
import { GroupsService } from '../groups.service';

@Component({
  selector: 'ux-groups-create-update',
  templateUrl: './groups-create-update.component.html',
  styleUrls: ['./groups-create-update.component.scss']
})
export class GroupsCreateUpdateComponent implements OnInit {

  form: UntypedFormGroup;
  mode: 'create' | 'update' = 'create';

  constructor(@Inject(MAT_DIALOG_DATA) public defaults: any,
              private dialogRef: MatDialogRef<GroupsCreateUpdateComponent>,
              private fb: UntypedFormBuilder,
              private groupsService: GroupsService
              ) {
  }

  ngOnInit() {
    if (this.defaults) {
      this.mode = 'update';
    } else {
      this.defaults = {} as Groups;
    }

    this.form = this.fb.group({
      group_id: this.defaults._id || '',
      group_name: this.defaults.group_name,
      group_description: [this.defaults.group_description || ''],
      status: this.defaults.status || '1',
      is_admin: this.defaults.is_admin || false
    });
  }

  save() {
    if (this.mode === 'create') {
      this.createGroups();
    } else if (this.mode === 'update') {
      this.updateGroups();
    }
  }

  createGroups() {
    const groups = this.form.value;
    this.dialogRef.close(groups);
  }

  updateGroups() {
    const groups = this.form.value;
    groups._id = this.defaults._id;

    this.dialogRef.close(groups);
  }

  isCreateMode() {
    return this.mode === 'create';
  }

  isUpdateMode() {
    return this.mode === 'update';
  }
}
